### src/lib/result.ts

```typescript
export type Result<T, E = Error> =
  | { ok: true;  value: T }
  | { ok: false; error: E };

export function ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

export function isOk<T, E>(r: Result<T, E>): r is { ok: true; value: T } {
  return r.ok === true;
}

export function isErr<T, E>(r: Result<T, E>): r is { ok: false; error: E } {
  return r.ok === false;
}

// Unwrap or throw
export function unwrap<T, E>(r: Result<T, E>): T {
  if (r.ok) return r.value;
  throw r.error;
}

// Map over success value
export function mapResult<T, U, E>(
  r: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return r.ok ? ok(fn(r.value)) : r;
}
```

## Code Review

🔴 **Critical: No error handling**
- `JSON.parse()` throws `SyntaxError` on invalid JSON
- Accessing `data.user.name` will throw if `user` is `null` or `undefined`

🔴 **Critical: No type safety**
- `data` is typed as `any`, bypassing TypeScript's safety net

### Fixed version

```typescript
interface UserData {
  user?: { name?: string };
}

function getUserName(input: string): string | null {
  let data: UserData;
  try {
    data = JSON.parse(input) as UserData;
  } catch {
    return null; // or throw a typed error
  }
  return data?.user?.name ?? null;
}
```
